A debounce function delays the execution of a function until after a certain amount of time has passed since the last time it was invoked.

```javascript
function debounce(func, delay) {
  let timeout;
  return function(...args) {
    const context = this;
    clearTimeout(timeout);
    timeout = setTimeout(() => func.apply(context, args), delay);
  };
}

// Example Usage:

function search(query) {
  console.log("Searching for:", query);
}

const debouncedSearch = debounce(search, 500); // Wait 500ms before calling search

// Simulate rapid typing
debouncedSearch("apple");
debouncedSearch("apples");
debouncedSearch("apple su");
debouncedSearch("apple store"); // This will be the only one that logs after 500ms

// After a 500ms pause, "Searching for: apple store" will be logged.
```
